#include <iostream>

using namespace std;

struct TreeNode
{
    int data;
    TreeNode *left;
    TreeNode *right;
};

TreeNode *insert(TreeNode *node, int value)
{
    if (node == nullptr) return new TreeNode{value, nullptr, nullptr};
    if (value < node->data) node->left = insert(node->left, value);
    else node->right = insert(node->right, value);
    return node;
}

void inorder(TreeNode *node)
{
    if (node == nullptr) return; // BASE CASE

    inorder(node->left);          // LEFT
    cout << node->data << " ";    // NODE
    inorder(node->right);         // RIGHT
}

int main()
{
    TreeNode *root = nullptr;
    root = insert(root, 8);
    root = insert(root, 3);
    root = insert(root, 10);
    root = insert(root, 6);
    root = insert(root, 1);

    inorder(root);

    return 0;
}

